#pragma once

#include <cstddef>
#include <type_traits>
#include <atomic>
#include <cstring>
#include <stdexcept>
#include <new>

namespace cccs {  // claude-code-cpp-study

template<typename T, size_t Capacity>
class RingBuffer {
    static_assert((Capacity & (Capacity - 1)) == 0,
                  "Capacity must be a power of 2");
    static_assert(Capacity > 0,
                  "Capacity must be positive");
    static_assert(std::is_trivially_copyable_v<T>,
                  "T must be trivially copyable for memcpy-based operations");

public:
    using value_type = T;
    using size_type = size_t;

    RingBuffer() noexcept : head_(0), tail_(0) {}

    // Non-copyable, non-movable (atomic members)
    RingBuffer(const RingBuffer&) = delete;
    RingBuffer& operator=(const RingBuffer&) = delete;
    RingBuffer(RingBuffer&&) = delete;
    RingBuffer& operator=(RingBuffer&&) = delete;

    [[nodiscard]] bool empty() const noexcept {
        return head_.load(std::memory_order_acquire) ==
               tail_.load(std::memory_order_acquire);
    }

    [[nodiscard]] bool full() const noexcept {
        size_t h = head_.load(std::memory_order_acquire);
        size_t t = tail_.load(std::memory_order_acquire);
        return (t - h) == Capacity;
    }

    [[nodiscard]] size_type size() const noexcept {
        return tail_.load(std::memory_order_acquire) -
               head_.load(std::memory_order_acquire);
    }

    [[nodiscard]] static constexpr size_type capacity() noexcept {
        return Capacity;
    }

    // Single-element push (move semantics)
    bool push(const T& item) {
        return push_impl(item);
    }

    bool push(T&& item) {
        return push_impl(std::move(item));
    }

    // Single-element pop
    bool pop(T& item) {
        size_t h = head_.load(std::memory_order_relaxed);
        size_t t = tail_.load(std::memory_order_acquire);

        if (h == t) return false;  // empty

        item = buffer_[h & (Capacity - 1)];
        head_.store(h + 1, std::memory_order_release);
        return true;
    }

    // Batch push — returns count successfully pushed
    size_type push_batch(const T* items, size_type count) {
        size_t h = head_.load(std::memory_order_relaxed);
        size_t t = tail_.load(std::memory_order_acquire);
        size_t available = Capacity - (t - h);

        if (available == 0 || count == 0) return 0;
        size_t to_push = (count < available) ? count : available;
        size_t idx = t & (Capacity - 1);

        // Split write if wrapped
        size_t first_chunk = Capacity - idx;
        if (to_push <= first_chunk) {
            std::memcpy(&buffer_[idx], items, to_push * sizeof(T));
        } else {
            std::memcpy(&buffer_[idx], items, first_chunk * sizeof(T));
            std::memcpy(&buffer_[0], items + first_chunk,
                        (to_push - first_chunk) * sizeof(T));
        }

        tail_.store(t + to_push, std::memory_order_release);
        return to_push;
    }

    // Batch pop — returns count successfully popped
    // NOTE: This is the method that had an off-by-one bug in the
    // original Claude Code output (v1, 2025-06). Fixed manually
    // after 3 dialogue iterations. See conversation_logs/case1_fix.md
    size_type pop_batch(T* items, size_type count) {
        size_t h = head_.load(std::memory_order_relaxed);
        size_t t = tail_.load(std::memory_order_acquire);

        if (h == t || count == 0) return 0;

        size_t available = t - h;
        size_t to_pop = (count < available) ? count : available;
        size_t idx = h & (Capacity - 1);

        // Split read if wrapped — fixed off-by-one: was first_chunk = Capacity - idx + 1
        size_t first_chunk = Capacity - idx;
        if (to_pop <= first_chunk) {
            std::memcpy(items, &buffer_[idx], to_pop * sizeof(T));
        } else {
            std::memcpy(items, &buffer_[idx], first_chunk * sizeof(T));
            std::memcpy(items + first_chunk, &buffer_[0],
                        (to_pop - first_chunk) * sizeof(T));
        }

        head_.store(h + to_pop, std::memory_order_release);
        return to_pop;
    }

private:
    template<typename U>
    bool push_impl(U&& item) {
        size_t h = head_.load(std::memory_order_acquire);
        size_t t = tail_.load(std::memory_order_relaxed);

        if ((t - h) == Capacity) return false;  // full

        buffer_[t & (Capacity - 1)] = std::forward<U>(item);
        tail_.store(t + 1, std::memory_order_release);
        return true;
    }

    // Cache-line padded to prevent false sharing
    // 64 bytes = typical x86 cache line size
    alignas(64) T buffer_[Capacity];
    alignas(64) std::atomic<size_type> head_{0};
    alignas(64) std::atomic<size_type> tail_{0};
};

} // namespace cccs
